export const HTBM_BANNER_CID = 'LOGOCID';
export const HTBM_SITE_URL = 'https://sitehtbm.netlify.app/';

// Bloc signature : prénom (Georgia bleu nuit) + poste (Arial doré italique) + bannière cliquable.
// `nom` = prénom de la personne en shift pour une réponse CLIENT, « Junior » pour une note interne.
export function signatureHtml(nom: string, poste: string): string {
  return (
    `<div style="margin-top:18px">` +
    `<div style="font-family:Georgia,serif;font-size:16pt;font-weight:bold;color:rgb(26,27,53)">${nom}</div>` +
    `<div style="font-family:Arial,sans-serif;font-weight:bold;font-style:italic;color:rgb(197,160,89)">${poste}</div>` +
    `<a href="${HTBM_SITE_URL}">` +
    // width=320 OBLIGATOIRE : sans contrainte, le PNG s'affiche à sa taille native et écrase le mail.
    `<img src="cid:${HTBM_BANNER_CID}" width="320" ` +
    `style="width:320px;max-width:320px;height:auto;border:0;display:block;margin-top:10px">` +
    `</a></div>`
  );
}

// Pièce jointe inline à joindre au sendMail : le contentId DOIT valoir le cid: de l'<img>,
// sinon l'image s'affiche cassée.
export function signatureAttachment(): Record<string, unknown> {
  return {
    '@odata.type': '#microsoft.graph.fileAttachment',
    name: 'signature-htbm.png',
    contentType: 'image/png',
    isInline: true,
    contentId: HTBM_BANNER_CID,
    contentBytes: HTBM_BANNER_PNG_BASE64,
  };
}
